// ==========================================
// 📘 CLOSURES IN JAVASCRIPT
// ==========================================

// Closure = Function + its lexical scope


function init() {
    let name = "Mozilla";
    function displayName() {
        console.log(name);
    }
    displayName();
}

// init();


// ==========================================
// 📘 Lexical Scoping Example
// ==========================================

function outer(){
    let username = "hitesh"

    function inner(){
        console.log("inner", username);
    }

    function innerTwo(){
        console.log("innerTwo", username);
        // console.log(secret); // ❌ Cannot access
    }

    inner()
    innerTwo()
}

// outer();

// ==========================================
// 📘 Classic Closure Example
// ==========================================

function makeFunc(){
    const name = "Mozilla";
    function displayName(){
        console.log(name);
    }
    return displayName;
}

const myFunc = makeFunc()
// myFunc()  // Still remembers 'name' variable


// ==========================================
// 📘 Practical Use Case - Click Handler
// ==========================================

function clickHandler(color){
    return function(){
        document.body.style.backgroundColor = color
    }
}

document.getElementById('orange').onclick = clickHandler("orange")
document.getElementById('green').onclick = clickHandler("green")

// ==========================================
// 📘 Interview Definition
// ==========================================

/*
A Closure is a function that remembers the variables from its lexical scope even after the outer function has finished executing.

Key Points:
- Inner function remembers outer variables
- Forms when function is returned
- Used in: event handlers, data privacy, function currying, module pattern
*/
